<template>
  <div :v-model="ProductList">
    <a-descriptions bordered title="产品基本信息" size="small">
      <a-descriptions-item label="产品编号">{{
        ProductList.testProduct.productCode
      }}</a-descriptions-item>
      <a-descriptions-item label="产品名称">{{
        ProductList.testProduct.productName
      }}</a-descriptions-item>
      <a-descriptions-item label="产品用途">{{
        ProductList.testProduct.productPurpose
      }}</a-descriptions-item>
      <a-descriptions-item label="产品类型">{{
        ProductList.productTypeName
      }}</a-descriptions-item>
      <a-descriptions-item label="是否可用">{{
        ProductList.testProduct.isValid == 1 ? "是" : "否"
      }}</a-descriptions-item>
      <a-descriptions-item label="产品规格等级">
        <p v-for="(item, index) in ProductList.specsList" :key="index">
          {{ index + 1 }}、{{ item }}
        </p>
      </a-descriptions-item>
      <a-descriptions-item label="产品判定依据">
        <p v-for="item in ProductList.standardList" :key="item">
          《{{ item }}》
        </p>
      </a-descriptions-item>
      <a-descriptions-item label="产品备注">{{
        ProductList.testProduct.remark
      }}</a-descriptions-item>
    </a-descriptions>


    <a-descriptions bordered :title="labAdd('产品检测项',index)" size="small" v-for="(item,index) in ProductList.testProductItemSelVoList" :key="index">
      <a-descriptions-item label="产品检测项编号">{{item.testProductItem.checkItemCode}}</a-descriptions-item>
      <a-descriptions-item label="产品检测项名称">{{item.testProductItem.checkItemName}}</a-descriptions-item>
      <a-descriptions-item label="产品检测项模板">{{item.reportName}}</a-descriptions-item>
      <a-descriptions-item label="检测项在报告中的位置坐标">{{item.testProductItem.coordinate}}</a-descriptions-item>
      <a-descriptions-item label="检测项图标">
        <img :src="item.testProductItem.icon" alt="" style="whild: 50px; height: 50px"/>
      </a-descriptions-item>
      <a-descriptions-item label="附加费用">{{item.testProductItem.additionalFees}}</a-descriptions-item>
      <a-descriptions-item label="物流费用">{{item.testProductItem.logisticsCosts}}</a-descriptions-item>
      <a-descriptions-item label="检测价格">{{item.testProductItem.checkPrice}}</a-descriptions-item>
      <a-descriptions-item label="检测项单位（1点，2样）">{{item.testProductItem.unit}}</a-descriptions-item>
      <a-descriptions-item label="是否有效">{{item.testProductItem.isAvailable}}</a-descriptions-item>
      <a-descriptions-item label="取样数量">{{item.testProductItem.sampleCount}}</a-descriptions-item>
      <a-descriptions-item label="实验地点">{{item.testProductItem.place}}</a-descriptions-item>
      <a-descriptions-item label="实验检测时长">{{item.testProductItem.duration}}</a-descriptions-item>
      <a-descriptions-item label="取样频率">{{item.testProductItem.frequency}}</a-descriptions-item>
      <a-descriptions-item label="技术难度">{{item.testProductItem.difficulty}}</a-descriptions-item>

      <a-descriptions-item label="检测方法">
        <p v-for="(items, indexs) in item.methodList" :key="indexs">
          {{ indexs + 1 }}、{{ items }}
        </p>
        </a-descriptions-item>
      <a-descriptions-item label="检测设备">
        <p v-for="(items, indexs) in item.typeList" :key="indexs">
          {{ indexs + 1 }}、{{ items }}
        </p>
        </a-descriptions-item>
      <a-descriptions-item label="检测依据">
        <p v-for="(items, indexs) in item.itemStandardList" :key="indexs">
          《{{ items }}》
        </p>
        </a-descriptions-item>
      <a-descriptions-item label="备注">{{item.testProductItem.remark}}</a-descriptions-item>
    </a-descriptions>
  </div>
</template>

<script>
import { getProductItemSel } from "@/server/http/api/Product";
export default {
  name: "QueryList",
  components: {},
  props: {
    productId: 0,
  },
  data() {
    return {
      ProductList: {
        testProduct: {},
        productTypeName: "",
        specsList: [],
        standardList: [],
        TestProductItemSelVoList: [],
      },
    };
  },
  created() {
    this.getList();
  },
  methods: {
    labAdd(value,index){
      return value+(index+1);
    },
    getList() {
      getProductItemSel(this.productId).then((res) => {
        this.ProductList = res.data.data;
      });
    },
  },
};
</script>

<style lang="less" scoped>
.search {
  margin-bottom: 54px;
}
.fold {
  width: calc(100% - 216px);
  display: inline-block;
}
.operator {
  margin-bottom: 18px;
}
@media screen and (max-width: 900px) {
  .fold {
    width: 100%;
  }
}
</style>