<template>
  <a-card>
    <div v-show="!ifProductOpen">
      <div :class="advanced ? 'search' : null">
        <a-form layout="horizontal">
          <div :class="advanced ? null : 'fold'">
            <a-row>
              <a-col :md="8" :sm="24">
                <a-form-item
                  label="产品名称"
                  :labelCol="{ span: 5 }"
                  :wrapperCol="{ span: 18, offset: 1 }"
                >
                  <a-input
                    placeholder="请选择产品类型名称"
                    v-model:value="queryParams.productName"
                  />
                </a-form-item>
              </a-col>
              <a-col :md="8" :sm="24">
                <a-form-item
                  label="产品类型"
                  :labelCol="{ span: 5 }"
                  :wrapperCol="{ span: 18, offset: 1 }"
                >
                  <a-select
                    :allowClear="true"
                    showSearch
                    optionFilterProp="lable"
                    v-model:value="queryParams.productTypeId"
                    placeholder="请选择产品类型"
                  >
                    <a-select-option
                      v-for="item in productTypeIdList"
                      :key="item.productTypeId"
                      :lable="
                        lableSelect(item.productTypeId, item.productTypeName)
                      "
                      :value="item.productTypeId"
                    >
                      {{
                        lableSelect(item.productTypeId, item.productTypeName)
                      }}
                    </a-select-option>
                  </a-select>
                </a-form-item>
              </a-col>
            </a-row>
          </div>
          <span style="float: right; margin-top: 3px">
            <a-button type="primary" @click="handleSearch">查询</a-button>
            <a-button style="margin-left: 8px" @click="reset">重置</a-button>
            <a @click="toggleAdvanced" style="margin-left: 8px">
              {{ advanced ? "收起" : "展开" }}
            </a>
          </span>
        </a-form>
      </div>
      <div>
        <a-space class="operator">
          <a-button @click="handleAdd" type="primary">添加</a-button>
          <a-button
            @click="handleUpdate"
            type="primary"
            :disabled="selectedRowKeys.length == 1 ? false : true"
            >编辑</a-button
          >
          <a-button
            @click="handleDel"
            type="primary"
            :disabled="selectedRowKeys.length > 0 ? false : true"
            danger
            >删除
          </a-button>
          <a-button
            @click="handleAdditem"
            type="primary"
            :disabled="selectedRowKeys.length == 1 ? false : true"
            >产品检测项</a-button
          >
        </a-space>
        <a-table
          rowKey="productId"
          :pagination="false"
          :columns="columns"
          :data-source="dataSource"
          :row-selection="{
            selectedRowKeys: selectedRowKeys,
            onChange: onSelectChange,
          }"
        >
        </a-table>
        <a-pagination
          v-show="total > 0"
          show-size-changer
          :show-total="(total) => `共 ${total} 条`"
          v-model:current="queryParams.current"
          v-model:pageSize="queryParams.size"
          :total="total"
          show-less-items
          @showSizeChange="onShowSizeChange"
          @change="onPageChange"
        />
      </div>
    </div>
    <a-modal
      :visible="open"
      :title="title"
      width="650px"
      @ok="handleOk"
      @cancel="handleCancel"
    >
      <a-form :model="form.testProduct" :rules="rules">
        <a-row :gutter="[16, 16]">
          <a-col :span="12">
            <a-form-item
              label="编&nbsp; &nbsp; &nbsp; &nbsp;号"
            >
              <a-input
                placeholder="请输入产品编号"
                v-model:value="form.testProduct.productCode"
              />
            </a-form-item>
          </a-col>
          <a-col :span="12">
            <a-form-item label="产品名称" name="productName">
              <a-input
                placeholder="请输入产品名称"
                v-model:value="form.testProduct.productName"
              />
            </a-form-item>
          </a-col>
        </a-row>
        <a-row :gutter="[16, 16]">
          <a-col :span="12">
            <a-form-item label="产品用途">
              <a-input
                placeholder="请输入产品用途"
                v-model:value="form.testProduct.productPurpose"
              />
            </a-form-item>
          </a-col>
          <a-col :span="12">
            <a-form-item label="产品类型" :rules="[{ required: true }]">
              <a-select
                :allowClear="true"
                showSearch
                optionFilterProp="lable"
                v-model:value="form.testProduct.productTypeId"
                placeholder="请选择产品类型"
              >
                <a-select-option
                  v-for="item in productTypeIdList"
                  :key="item.productTypeId"
                  :lable="lableSelect(item.productTypeId, item.productTypeName)"
                  :value="item.productTypeId"
                >
                  {{ lableSelect(item.productTypeId, item.productTypeName) }}
                </a-select-option>
              </a-select>
            </a-form-item>
          </a-col>
        </a-row>
        <a-row :gutter="[16, 16]">
          <a-col :span="24">
            <a-form-item label="产品判定依据">
              <a-select
                :allowClear="true"
                v-model:value="form.standardRelIds"
                mode="multiple"
                optionFilterProp="lable"
                placeholder="请选择产品判定依据"
              >
                <a-select-option
                  v-for="item in standardRelIdList"
                  :key="item.id"
                  :lable="lableSelect(item.code, item.name)"
                  :value="item.id"
                >
                  {{ lableSelect(item.code, item.name) }}
                </a-select-option>
              </a-select>
            </a-form-item>
          </a-col>
        </a-row>
        <a-row
          :gutter="[16, 16]"
          v-for="(item, index) in form.specsList"
          :key="index"
        >
          <a-col :span="21">
            <a-form-item :label="specsLab('规格等级', index)">
              <a-input
                :placeholder="specsLab('请输入规格等级', index)"
                v-model:value="form.specsList[index]"
              />
            </a-form-item>
          </a-col>
          <a-col :span="1" v-if="index == form.specsList.length - 1">
            <a-button
              type="primary"
              shape="circle"
              size="small"
              @click="addSpecs"
            >
              <template #icon>
                <PlusOutlined />
              </template>
            </a-button>
          </a-col>
          <a-col :span="1">
            <a-button
              v-if="form.specsList.length > 1"
              type="primary"
              shape="circle"
              size="small"
              danger
              @click="delSpecs(index)"
            >
              <template #icon>
                <MinusOutlined />
              </template>
            </a-button>
          </a-col>
        </a-row>

        <a-row :gutter="[16, 16]">
          <a-col :span="24">
            <a-form-item label="产品备注">
              <a-textarea
                rows="4"
                placeholder="请输入产品备注"
                v-model:value="form.testProduct.remark"
                show-count
                :maxlength="500"
              />
            </a-form-item>
          </a-col>
        </a-row>
      </a-form>
    </a-modal>
    <div v-show="ifProductOpen">
      <p>
        <a-button type="link" @click="previousStep">&lt;&lt;产品列表</a-button>
      </p>
      <div>
        <div>
          <product-item ref="item" :productId="productId"></product-item>
        </div>
      </div>
    </div>
  </a-card>
</template>

<script>
const columns = [
  {
    title: "ID",
    dataIndex: "productId",
  },
  {
    title: "编号",
    dataIndex: "productCode",
  },
  {
    title: "产品名称",
    dataIndex: "productName",
  },
  {
    title: "产品类型",
    dataIndex: "productTypeName",
  },
  {
    title: "产品用途",
    dataIndex: "productPurpose",
  },
];
const rules = {
  productName: [{ required: true, message: "该为必填项", trigger: "blur" }],
};
import {
  ProductList,
  addProduct,
  getProduct,
  delProduct,
  editProduct,
  ProductTypeListAll,
} from "@/server/http/api/Product";
import { ExclamationCircleOutlined } from "@ant-design/icons-vue";
import { createVNode } from "vue";
import { Modal } from "ant-design-vue";
import { testListAll } from "@/server/http/api/teststand";
import { PlusOutlined, MinusOutlined } from "@ant-design/icons-vue";
import productItem from "../../views/product/productItem.vue";
import ProductSel from "../../views/product/productSel.vue";
import { message } from "ant-design-vue";
export default {
  name: "QueryList",
  components: { PlusOutlined, MinusOutlined, ProductSel, productItem },
  data() {
    return {
      // 弹出层标题
      title: "",
      // 是否显示弹出层
      open: false,
      advanced: false,
      columns: columns,
      rules:rules,
      //存储查询到的产品表格信息
      dataSource: [],
      selectedRows: [],
      //记录产品选择key值
      selectedRowKeys: [],
      // 表单参数
      form: {
        testProduct: {},
        standardRelIds: [],
        specsList: [""],
      },
      Pagination: {},
      total: 0,
      queryParams: {
        current: 1,
        size: 10,
        productName: undefined,
        productTypeId: undefined,
      },
      // 选中数组
      ids: [],
      // 非单个禁用
      single: true,
      // 非多个禁用
      multiple: true,
      //产品类型
      productTypeIdList: [],
      //产品判定依据
      standardRelIdList: [],
      //是否进入到产品管理页
      ifProductOpen: false,
      //保存产品ID
      productId: null,
    };
  },
  authorize: {
    deleteRecord: "delete",
  },
  created() {
    this.getList();
  },
  mounted() {
    this.getproductTypeIdList();
    this.gettestList();
  },
  methods: {
    //拼接select
    lableSelect(code, name) {
      return code + " " + name;
    },
    //点击完成
    save() {
      this.previousStep();
    },
    //添加等级input
    addSpecs() {
      this.form.specsList.push("");
    },
    //删除等级input
    delSpecs(index) {
      this.form.specsList.splice(index, 1);
    },
    //拼接相应字符
    specsLab(e, index) {
      return e + "(" + (index + 1) + ")";
    },
    //获取产品分类
    getproductTypeIdList() {
      ProductTypeListAll().then((res) => {
        var data = res.data;
        this.productTypeIdList = data.data;
      });
    },
    //获取产品判定依据
    gettestList() {
      testListAll({ type: 1 }).then((res) => {
        var data = res.data;
        this.standardRelIdList = data.data;
      });
    },
    onShowSizeChange(current, pageSize) {
      this.queryParams.current = current;
      this.queryParams.size = pageSize;
      this.getList();
    },
    onPageChange(pageNumber) {
      this.queryParams.current = pageNumber;
      this.getList();
    },
    //获取产品列表
    getList() {
      ProductList(this.queryParams).then((res) => {
        var data = res.data;
        this.dataSource = data.data.records;
        this.total = data.data.total;
      });
    },
    //查询数据
    handleSearch() {
      this.getList();
    },
    reset() {
      this.queryParams = {
        current: 1,
        size: 10,
        productName: undefined,
        productTypeId: undefined,
      };
      this.getList();
    },
    handleOk(e) {
      if (
        !this.form.testProduct.productName ||
        !this.form.testProduct.productTypeId
      ) {
        message.warning("缺少必填参数!");
        return;
      }
      this.submitForm();
    },
    handleCancel(e) {
      this.previousStep();
    },
    deleteRecord(key) {
      this.dataSource = this.dataSource.filter((item) => item.key !== key);
      this.selectedRows = this.selectedRows.filter((item) => item.key !== key);
    },
    toggleAdvanced() {
      this.advanced = !this.advanced;
    },
    onSelectChange(selection) {
      this.ids = selection.map((item) => item.id);
      this.single = selection.length !== 1;
      this.multiple = !selection.length;
      this.selectedRowKeys = selection;
    },
    onSelectChangeItem(selection) {
      this.ids = selection.map((item) => item.id);
      this.single = selection.length !== 1;
      this.multiple = !selection.length;
      this.selectedRowKeys = selection;
    },
    /** 新增按钮操作 */
    handleAdd() {
      this.title = "添加产品";
      this.open = true;
    },
    /**产品检测项按钮操作 */
    handleAdditem() {
      this.ifProductOpen = true;
      this.productId = this.selectedRowKeys[0];
    },
    /** 修改按钮操作 */
    handleUpdate() {
      getProduct(this.selectedRowKeys[0]).then((response) => {
        this.form = response.data.data;
        if (this.form.specsList != null && this.form.specsList.length == 0) {
          this.form.specsList = [""];
        }
        this.open = true;
        this.title = "修改产品";
      });
    },
    //删除按钮
    handleDel() {
      let that = this;
      Modal.confirm({
        title: "请确认删除（已选择 " + that.selectedRowKeys.length + " 项）",
        icon: createVNode(ExclamationCircleOutlined),
        okText: "确认",
        okType: "取消",
        okType: "danger",
        cancelText: "取消",
        onOk() {
          delProduct(that.selectedRowKeys)
            .then((response) => {
              that.selectedRowKeys = [];
              that.getList();
            })
            .finally(() => {
              that.buttonLoading = false;
            });
        },
        onCancel() {
          that.getList();
        },
      });
    },
    //产品管理***返回
    previousStep() {
      this.current = 0;
      this.form = {
        testProduct: {},
        standardRelIds: [],
        specsList: [""],
      };
      this.ifProductOpen = false;
      this.open = false;
      this.$refs.item.dataSource = [];
      this.getList();
    },
    submitForm() {
      if (this.form.testProduct.productId != null) {
        editProduct(this.form).then((response) => {
          this.previousStep();
        });
      } else {
        addProduct(this.form).then((response) => {
          this.previousStep();
        });
      }
    },
  },
};
</script>

<style lang="less" scoped>
.search {
  margin-bottom: 54px;
}
.fold {
  width: calc(100% - 216px);
  display: inline-block;
}
.operator {
  margin-bottom: 18px;
}
@media screen and (max-width: 900px) {
  .fold {
    width: 100%;
  }
}
.steps-content {
  margin: 0 auto;
  width: 80%;
  margin-top: 16px;
  border: 1px dashed #e9e9e9;
  border-radius: 6px;
  text-align: center;
  padding-top: 20px;
}
.steps-content-item {
  margin: 0 auto;
  width: 80%;
  margin-top: 16px;
  border: 1px dashed #e9e9e9;
  border-radius: 6px;
  text-align: center;
}

.steps-action {
  margin-top: 24px;
  float: right;
}
</style>
